INSERT INTO public.characters (id, name, name_jp, role, description, image_url, age, gender, abilities) VALUES (1, 'Эрен Йегер', 'エレン・イェーガー', 'main', 'Главный герой. Одержим желанием обрести свободу. Его путь от солдата до разрушителя мира — центр всей саги.', 'https://cdn.myanimelist.net/images/characters/10/216895.jpg', '19', 'М', 'Атакующий Титан, Основополагающий Титан, Координата');
INSERT INTO public.characters (id, name, name_jp, role, description, image_url, age, gender, abilities) VALUES (2, 'Микаса Аккерман', 'ミカサ・アッカーマン', 'main', 'Лучший солдат своего поколения. Приёмная сестра Эрена с уникальными боевыми способностями клана Аккерман.', 'https://cdn.myanimelist.net/images/characters/9/215563.jpg', '19', 'Ж', 'Способности клана Аккерман');
INSERT INTO public.characters (id, name, name_jp, role, description, image_url, age, gender, abilities) VALUES (3, 'Армин Арлерт', 'アルミン・アルレルト', 'main', 'Гениальный тактик. Лучший друг Эрена, чей интеллект не раз спасал человечество.', '', '19', 'М', 'Колоссальный Титан, стратегическое мышление');
INSERT INTO public.characters (id, name, name_jp, role, description, image_url, age, gender, abilities) VALUES (4, 'Лайт Ягами', '夜神月', 'main', 'Блестящий студент, нашедший Тетрадь смерти. Стал богом нового мира.', 'https://cdn.myanimelist.net/images/characters/3/253266.jpg', '17', 'М', 'Тетрадь смерти, высокий интеллект');
INSERT INTO public.characters (id, name, name_jp, role, description, image_url, age, gender, abilities) VALUES (5, 'Л', 'エル', 'main', 'Величайший детектив мира.', 'https://cdn.myanimelist.net/images/characters/5/45867.jpg', '25', 'М', 'Дедуктивное мышление');
INSERT INTO public.characters (id, name, name_jp, role, description, image_url, age, gender, abilities) VALUES (6, 'Мисса', 'ミサ・アマネ', 'supporting', 'Вторая владелица Тетради смерти. Поклонница Киры.', '', '19', 'Ж', 'Тетрадь смерти, Глаза смерти');
INSERT INTO public.characters (id, name, name_jp, role, description, image_url, age, gender, abilities) VALUES (7, 'Юджи Итадори', '虎杏悠仁', 'main', 'Добродушный юноша со сверхсилой, ставший сосудом Сукуны.', '', '15', 'М', 'Сверхсила, Чёрная вспышка');
INSERT INTO public.characters (id, name, name_jp, role, description, image_url, age, gender, abilities) VALUES (8, 'Нобара Кугисаки', '釘崎野薔薇', 'main', 'Заклинательница из деревни. Использует молоток и гвозди.', '', '16', 'Ж', 'Техника молотка и гвоздей');
INSERT INTO public.characters (id, name, name_jp, role, description, image_url, age, gender, abilities) VALUES (9, 'Фриерен', 'フリーレン', 'main', 'Эльфийская волшебница, пережившая своих спутников. Путешествует, чтобы понять людей.', '', '1000+', 'Ж', 'Высший уровень магии');
INSERT INTO public.characters (id, name, name_jp, role, description, image_url, age, gender, abilities) VALUES (10, 'Ферн', 'フェルン', 'main', 'Ученица Фрирен. Талантливая молодая волшебница.', '', '18', 'Ж', 'Магия, скорость заклинаний');
INSERT INTO public.characters (id, name, name_jp, role, description, image_url, age, gender, abilities) VALUES (11, 'Старк', 'シュタルク', 'main', 'В раннем возрасте осиротел и был взят на воспитание Айзеном. По просьбе наставника присоединился к отряду Фрирен в качестве воина.', NULL, '19', 'М', 'Техника ударов секирой');
INSERT INTO public.characters (id, name, name_jp, role, description, image_url, age, gender, abilities) VALUES (12, 'Джет Блэк', 'ジェット・ブラック', 'main', 'Джет, известный на своем домашнем спутнике как "Черный пес" за свое упорство, - 36-летний бывший полицейский из Ганимеда (спутника Юпитера), который во время сериала выступает в роли противника Спайка. Физически Джет очень высокий, мускулистого телосложения. Он носит бороду без усов и совершенно лысый, за исключением затылка. Спайк ведет себя лениво и незаинтересованно, тогда как Джет трудолюбив и мастер на все руки.', 'http://localhost:3001/uploads/e76e4eae-7ffa-44a8-898a-052842e69b0e.jpg', NULL, 'М', NULL);
INSERT INTO public.characters (id, name, name_jp, role, description, image_url, age, gender, abilities) VALUES (13, 'Фэй Валентайн', 'フェイ・バレンタイン', 'main', 'В детстве она была обычной тихой девочкой, мечтающей о светлом будущем, но после катастрофы на Земле была заморожена в анабиозе и оживлена много лет спустя.', 'http://localhost:3001/uploads/0252ce31-54f4-4f2b-b7b0-1b3032997022.jpg', NULL, 'Ж', NULL);
INSERT INTO public.characters (id, name, name_jp, role, description, image_url, age, gender, abilities) VALUES (14, 'Наруто Узумаки', 'うずまき ナルト', 'main', NULL, 'http://localhost:3001/uploads/f899fbdc-5484-4235-99a6-0e788754292e.jpg', NULL, 'М', NULL);
INSERT INTO public.characters (id, name, name_jp, role, description, image_url, age, gender, abilities) VALUES (15, 'Сакура Харуно', '春野 サクラ', 'main', NULL, 'http://localhost:3001/uploads/3c59e9af-d25f-4861-b15b-df9a9c3be3ac.jpg', NULL, 'Ж', NULL);


